// Extract error details from the Error Trigger node
const errorData = $input.first().json;

const workflowName = errorData.workflow?.name || 'unknown';
const executionId = errorData.execution?.id || 'unknown';
const errorMessage = errorData.execution?.error?.message || 'Unknown error';
const errorNode = errorData.execution?.lastNodeExecuted || 'unknown';
const timestamp = new Date().toISOString();

// Map workflow names to error code prefixes
const workflowPrefix = {
  'w1-daily-quest-generator': 'W1',
  'w2-lobehub-command-handler': 'W2',
  'w3-daily-summary-reporter': 'W3',
  'w4-deferred-cleanup': 'W4',
};
const prefix = workflowPrefix[workflowName] || 'SYS';
const errorCode = `${prefix}_FATAL_ERROR`;

// Build notification message following F-3 pattern
const notification = `\u274C [${errorCode}] Fatal error in ${workflowName} at node '${errorNode}': ${errorMessage}. Check n8n execution ${executionId} for details.`;

return [{
  json: {
    success: false,
    data: {
      error_code: errorCode,
      workflow_name: workflowName,
      execution_id: executionId,
      error_node: errorNode,
      error_message: errorMessage,
      notification,
      timestamp
    },
    error: {
      code: errorCode,
      message: errorMessage
    },
    metadata: {
      step: 'w5_error_handler',
      timestamp,
      items_processed: 1,
      items_failed: 1
    }
  }
}];

// Check DRY_RUN mode before sending LobeHub notification
const dryRun = ($env.PULSE_DRY_RUN || 'false').toLowerCase();
const isDryRun = dryRun === 'true' || dryRun === '1';
const data = $input.first().json.data;

if (isDryRun) {
  console.log(`[DRY_RUN] Would send error notification to LobeHub: ${data.notification}`);
  return [{
    json: {
      dry_run: true,
      message: `[DRY_RUN] Would send error notification: ${data.error_code}`,
      notification: data.notification
    }
  }];
}

// Pass through for actual notification
return [{
  json: {
    should_notify: true,
    notification: data.notification,
    error_code: data.error_code
  }
}];

